import React from "react";
import styles from "./subscription.module.css";
import Option from "./option";
import { useTranslation } from "react-i18next";

const Subscription: React.FC = () => {
  const [t] = useTranslation("global");

  return (
    <div className={styles.wrapper_subscription}>
      <Option title={t("product-details.subscription.option1")} />
      <Option
        title={t("product-details.subscription.option2")}
        desc="Subscribe now and get the 10% of discount on every recurring order.  The discount will be applied at checkout."
        details="See details"
        isDropdown={true}
      />
    </div>
  );
};

export default Subscription;
